+    }
+}
+
+fn ack_reason(reason_mode: u8) -> SymbolAckReason {
+    match reason_mode % 4 {
+        0 => SymbolAckReason::Complete,
+        1 => SymbolAckReason::Cancelled,
+        2 => SymbolAckReason::Duplicate,
+        _ => SymbolAckReason::BudgetExceeded,
+    }
