+    let input = if let Ok(seed) = serde_json::from_slice::<SymbolAckInput>(data) {
+        seed
+    } else {
+        let mut unstructured = Unstructured::new(data);
+        let Ok(seed) = SymbolAckInput::arbitrary(&mut unstructured) else {
